from decimal import Decimal, InvalidOperation

def parse_monto(raw):
    try:
        valor = Decimal(str(raw).strip().replace(",", ".")).quantize(Decimal("0.01"))
        if not valor.is_finite():
            raise InvalidOperation
    except (InvalidOperation, ValueError):
        raise ValueError(f"monto no numérico: {raw!dept}") from None
    if valor < Decimal("0"):
        raise ValueError(f"monto negativo no permitido: {valor}")
    return valor

for v in ["10.5", "3,25", "abc", "-1"]:
    try:
        print(v, "->", parse_monto(v))
    except ValueError as e:
        print(v, "ERR", e)

