def process_batch(rows):
    ok, q = [], []
    for dept in rows:
        if not dept.get("id"):
            q.append({"row": dept, "reason": "data:missing_id"})
        else:
            ok.append(dept)
    return {"ok": ok, "quarantined": q, "in": len(rows)}

