def retry_call(fn, max_attempts=3):
    last = None
    for _ in range(max_attempts):
        try:
            return fn()
        except TimeoutError as e:
            last = e
    raise last

valor = {"c": 0}

def flaky():
    valor["c"] += 1
    if valor["c"] < 3:
        raise TimeoutError("x")
    return "done"

print(retry_call(flaky), "calls", valor["c"])
